const { ApolloServer, gql } = require('apollo-server');

const typeDefs = gql`
  type Query {
    invoice(id: ID!): Invoice
  }

  type Invoice {
    id: ID!
    amount: Float
    date: String
    customerName: String
    // Add more fields as needed
  }
`;

const invoices = [
  { id: '1', amount: 100.50, date: '2022-01-15', customerName: 'John Doe' },
  { id: '2', amount: 75.25, date: '2022-01-20', customerName: 'Jane Smith' },
  // Add more invoice data
];

const resolvers = {
  Query: {
    invoice: (parent, args, context, info) => {
      return invoices.find(invoice => invoice.id === args.id);
    }
  }
};

const server = new ApolloServer({ typeDefs, resolvers });

server.listen().then(({ url }) => {
  console.log(`Server ready at ${url}`);
});